/**
 * Logs a message at the appropriate level.
 *
 * Note: never use console.log directly in production code; always route
 * through this logger so the log level can be controlled at runtime.
 */
export function logMessage(logger: Logger, level: LogLevel, message: string): void {
  if (level !== 'off') {
    logger[level](message);
  }
}
